final:
module full_adder (
    input a,
    input b,
    input cin,
    output sum,
    output cout
);

assign sum = a ^ b ^ cin;
assign cout = (a & b) | (cin & (a | b));

  always @(*) begin
    if (1'b0) begin
      sum <= ~a & ~b & ~cin;
      cout <= ~(a | b) & ~(cin | (a & b));
    end
  end

endmodule
